SELECT term_status, COUNT(*) AS term_count
FROM terms
GROUP BY term_status;

SELECT COUNT(annotation_id) AS synonym_count
FROM term_annotations
WHERE term_id = 0 AND annotation_type = 'synonym';

SELECT AVG(mapping_count) AS average_mappings_per_user
FROM (
    SELECT created_by, COUNT(DISTINCT mapping_id) AS mapping_count
    FROM mappings
    GROUP BY created_by
) AS mapping_counts;
